export function getCentrisQuery(bedrooms: string): string {
	return JSON.stringify({
		query: {
			UseGeographyShapes: 0,
			Filters: [],
			FieldsValues: [
				{
					fieldId: "PropertyType",
					value: "RentCondo",
					fieldConditionId: "",
					valueConditionId: "IsResidentialForRent",
				},
				{
					fieldId: "Category",
					value: "Residential",
					fieldConditionId: "",
					valueConditionId: "",
				},
				{
					fieldId: "SellingType",
					value: "Rent",
					fieldConditionId: "",
					valueConditionId: "",
				},
				{
					fieldId: "Rooms",
					value: bedrooms,
					fieldConditionId: "IsResidentialNotLot",
					valueConditionId: "",
				},
				{
					fieldId: "LivingArea",
					value: "SquareFeet",
					fieldConditionId: "IsResidentialNotLot",
					valueConditionId: "",
				},
				{
					fieldId: "RentPrice",
					value: 0,
					fieldConditionId: "ForRent",
					valueConditionId: "",
				},
				{
					fieldId: "RentPrice",
					value: 999999999999,
					fieldConditionId: "ForRent",
					valueConditionId: "",
				},
			],
		},
		isHomePage: false,
	});
}

